function debounce(func, wait) {
    let timeoutId = null;
    let lastArgs = null;

    function debounced(...args) {
        lastArgs = args;
        if (timeoutId !== null) {
            clearTimeout(timeoutId);
        }
        timeoutId = setTimeout(() => {
            func.apply(this, lastArgs);
            timeoutId = null;
            lastArgs = null;
        }, wait);
    }

    debounced.cancel = function() {
        if (timeoutId !== null) {
            clearTimeout(timeoutId);
            timeoutId = null;
            lastArgs = null;
        }
    };

    debounced.flush = function() {
        if (timeoutId !== null) {
            clearTimeout(timeoutId);
            func.apply(this, lastArgs);
            timeoutId = null;
            lastArgs = null;
        }
    };

    return debounced;
}

