def flatten_dict(nested_dict):
    result = {}
    stack = [(nested_dict, '')]
    while stack:
        current, prefix = stack.pop()
        for key, value in current.items():
            full_key = f"{prefix}.{key}" if prefix else key
            if isinstance(value, dict) and value:
                stack.append((value, full_key))
            else:
                result[full_key] = value
    return result

import aiohttp
import asyncio
from collections import OrderedDict
import time
import hashlib
import json

class AsyncHTTPClient:
    def __init__(self, timeout=30, max_retries=3, cache_ttl=300, cache_size=100):
        self.timeout = aiohttp.ClientTimeout(total=timeout)
        self.max_retries = max_retries
        self.cache_ttl = cache_ttl
        self.cache_size = cache_size
        self._cache = OrderedDict()
        self._session = None

    async def _get_session(self):
        if self._session is None or self._session.closed:
            self._session = aiohttp.ClientSession(timeout=self.timeout)
        return self._session

    def _cache_key(self, method, url, data=None):
        raw = f"{method}:{url}:{json.dumps(data, sort_keys=True) if data else ''}"
        return hashlib.md5(raw.encode()).hexdigest()

    def _get_cached(self, key):
        if key in self._cache:
            entry = self._cache[key]
            if time.time() - entry['time'] < self.cache_ttl:
                self._cache.move_to_end(key)
                return entry['data']
            del self._cache[key]
        return None

    def _set_cached(self, key, data):
        self._cache[key] = {'data': data, 'time': time.time()}
        if len(self._cache) > self.cache_size:
            self._cache.popitem(last=False)

    async def _request(self, method, url, data=None, use_cache=True):
        cache_key = self._cache_key(method, url, data)
        if use_cache:
            cached = self._get_cached(cache_key)
            if cached is not None:
                return cached
        session = await self._get_session()
        last_error = None
        for attempt in range(self.max_retries):
            try:
                kwargs = {'json': data} if data else {}
                async with session.request(method, url, **kwargs) as resp:
                    resp.raise_for_status()
                    result = await resp.json()
                    if use_cache:
                        self._set_cached(cache_key, result)
                    return result
            except (aiohttp.ClientError, asyncio.TimeoutError) as e:
                last_error = e
                if attempt < self.max_retries - 1:
                    await asyncio.sleep(2 ** attempt)
        raise last_error

    async def get(self, url, use_cache=True):
        return await self._request('GET', url, use_cache=use_cache)

    async def post(self, url, data, use_cache=False):
        return await self._request('POST', url, data=data, use_cache=use_cache)

    async def close(self):
        if self._session and not self._session.closed:
            await self._session.close()

