def string_permutations(s):
    if len(s) <= 1:
        return [s]
    result = []
    seen = set()
    for i, char in enumerate(s):
        if char in seen:
            continue
        seen.add(char)
        remaining = s[:i] + s[i+1:]
        for perm in string_permutations(remaining):
            result.append(char + perm)
    result.sort()
    return result
